/* I2C EEPROM driver */
#ifndef EEPROM_DRV_H
#define EEPROM_DRV_H

#include <stdint.h>

/* Write bytes to EEPROM.
 * addr     : memory address within EEPROM
 * data     : pointer to source buffer
 * len      : number of bytes to write
 * Returns 0 on success. */
int eeprom_write(uint16_t addr, const uint8_t *data, uint16_t len);

/* Read bytes from EEPROM. */
int eeprom_read(uint16_t addr, uint8_t *data, uint16_t len);

/* Erase entire EEPROM contents (set to 0xFF). */
int eeprom_erase_all(void);

#endif

