/* I2C EEPROM driver */
#ifndef EEPROM_DRV_H
#define EEPROM_DRV_H

#include <stdint.h>

/* Device handle added to all functions to support multiple EEPROM devices */
typedef struct eeprom_dev eeprom_dev_t;

/* Write bytes to EEPROM.
 * dev      : device handle obtained from eeprom_open()
 * addr     : memory address within EEPROM
 * data     : pointer to source buffer
 * len      : number of bytes to write
 * Returns 0 on success. */
int eeprom_write(eeprom_dev_t *dev, uint16_t addr,
                 const uint8_t *data, uint16_t len);

/* Read bytes from EEPROM. */
int eeprom_read(eeprom_dev_t *dev, uint16_t addr,
                uint8_t *data, uint16_t len);

/* eeprom_erase_all() REMOVED — use eeprom_erase_range() instead */
int eeprom_erase_range(eeprom_dev_t *dev, uint16_t addr, uint16_t len);

#endif

